import{_ as o,C as n,o as l,c as s,E as i,w as e,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Moving to Lithuania","description":"Immigration pathways and relocation guide for Lithuania","frontmatter":{"layout":"doc","title":"Moving to Lithuania","description":"Immigration pathways and relocation guide for Lithuania"},"headers":[],"relativePath":"europe/lithuania/moving-there.md","filePath":"europe/lithuania/moving-there.md","lastUpdated":null}'),h={name:"europe/lithuania/moving-there.md"};function u(g,t,m,c,f,p){const a=n("Badge");return l(),s("div",null,[i(a,{variant:"green"},{default:e(()=>[...t[0]||(t[0]=[r("EU: Free Movement",-1)])]),_:1}),i(a,{variant:"yellow"},{default:e(()=>[...t[1]||(t[1]=[r("Non-EU: Work Visa",-1)])]),_:1}),i(a,{variant:"yellow"},{default:e(()=>[...t[2]||(t[2]=[r("No Specific DN Visa",-1)])]),_:1}),t[3]||(t[3]=d('<h1 id="moving-to-lithuania" tabindex="-1">Moving to Lithuania <a class="header-anchor" href="#moving-to-lithuania" aria-label="Permalink to &quot;Moving to Lithuania&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eea-eu-citizens" tabindex="-1">EEA/EU Citizens <a class="header-anchor" href="#eea-eu-citizens" aria-label="Permalink to &quot;EEA/EU Citizens&quot;">​</a></h3><ul><li><strong>Free movement rights</strong> — no visa required</li><li><strong>Up to 3 months</strong>: No registration needed</li><li><strong>Over 3 months</strong>: Register with the Migration Department (Migracijos departamentas)</li><li><strong>Right to work</strong>: Automatic</li><li><strong>Residence registration</strong>: Required at the municipality</li></ul><h3 id="uk-citizens-post-brexit" tabindex="-1">UK Citizens (Post-Brexit) <a class="header-anchor" href="#uk-citizens-post-brexit" aria-label="Permalink to &quot;UK Citizens (Post-Brexit)&quot;">​</a></h3><ul><li><strong>Schengen Area</strong>: Visa-free for up to 90 days in any 180-day period</li><li><strong>Long-term residency</strong>: Requires a residence permit: <ul><li>Work permit (job offer from Lithuanian employer)</li><li>Student visa (enrollment at Lithuanian university)</li><li>Family reunification</li><li>Start-up visa</li></ul></li></ul><h3 id="third-country-nationals" tabindex="-1">Third-Country Nationals <a class="header-anchor" href="#third-country-nationals" aria-label="Permalink to &quot;Third-Country Nationals&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visa Type</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Work Permit</td><td>Job offer from Lithuanian employer</td><td>Up to 2 years, renewable</td></tr><tr><td>Student Visa</td><td>Enrollment at accredited institution</td><td>Duration of studies</td></tr><tr><td>Family Reunification</td><td>Family ties to Lithuanian resident</td><td>Tied to sponsor&#39;s status</td></tr><tr><td>Start-up Visa</td><td>Innovative business, approved</td><td>Up to 2 years</td></tr><tr><td>EU Blue Card</td><td>Highly skilled (salary ~€30,000+/year)</td><td>Up to 4 years</td></tr></tbody></table><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h2><p>Lithuania does <strong>not have a dedicated digital nomad visa</strong>. Options for remote workers:</p><ul><li><strong>Start-up visa</strong> for entrepreneurs with an innovative business idea</li><li><strong>Work visa</strong> if employed by a Lithuanian company</li><li><strong>Tourist visa</strong> for up to 90 days (no work permitted)</li><li>Some remote workers use the <strong>short-term work visa</strong> for specific projects</li></ul><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] <strong>Passport</strong>: Valid for duration of stay</li><li>[ ] <strong>Visa</strong>: Apply 2-3 months in advance</li><li>[ ] <strong>Healthcare</strong>: Private health insurance initially; register with VLK after residency</li><li>[ ] <strong>HRT</strong>: Get 6-month supply and doctor&#39;s letter (translated to Lithuanian)</li><li>[ ] <strong>Banking</strong>: Consider Swedbank, SEB, or Revolut</li><li>[ ] <strong>Housing</strong>: Research rental market (aruodas.lt, domoplius.lt)</li><li>[ ] <strong>Language</strong>: Lithuanian essential for daily life; Russian helpful</li><li>[ ] <strong>Document translation</strong>: Official Lithuanian translations needed</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] Register with Migration Department (non-EU) or municipality (EU)</li><li>[ ] Obtain personal code (Asmens kodas) — essential for all services</li><li>[ ] Register with VLK (National Health Insurance Fund)</li><li>[ ] Open local bank account</li><li>[ ] Get local SIM card (Telia, Bitė, Tele2)</li><li>[ ] Connect with LGBTQ+ community (LGL, Trans Autonomija)</li><li>[ ] Register with Santaros Clinics for trans healthcare</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><ul><li><strong>Low to moderate</strong> — affordable EU destination</li><li>Monthly rent (1-bed): €350-650 (Vilnius), €250-450 (Kaunas), €200-400 (Klaipėda)</li><li>Monthly groceries: €250-350</li><li>Public transport: €30/month (Vilnius)</li><li>Dining out: €8-15 per meal</li></ul><h3 id="best-cities-for-lgbtq-community" tabindex="-1">Best Cities for LGBTQ+ Community <a class="header-anchor" href="#best-cities-for-lgbtq-community" aria-label="Permalink to &quot;Best Cities for LGBTQ+ Community&quot;">​</a></h3><table tabindex="0"><thead><tr><th>City</th><th>LGBTQ+ Scene</th><th>Trans Healthcare</th></tr></thead><tbody><tr><td><strong>Vilnius</strong></td><td>Moderate (growing scene)</td><td>Only option (Santaros)</td></tr><tr><td><strong>Kaunas</strong></td><td>Limited</td><td>None</td></tr><tr><td><strong>Klaipėda</strong></td><td>Very limited</td><td>None</td></tr></tbody></table><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><ul><li><strong>Winters</strong>: Cold (-5°C to -15°C), snow common, limited daylight (6-7 hours)</li><li><strong>Summers</strong>: Mild (15-25°C), long daylight until 10pm</li><li><strong>Best time to arrive</strong>: Late spring/summer (May-September)</li></ul><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><ul><li>Official language: Lithuanian (very distinct, challenging to learn)</li><li>Russian: Widely spoken, especially among older generations</li><li>English: Moderate, more common in Vilnius and among youth</li><li>Free Lithuanian language courses available for immigrants</li><li>Russian is very useful for daily interactions</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.migracija.lt/" target="_blank" rel="noreferrer">Migration Department (Migracijos departamentas)</a></li><li><a href="https://www.vlk.lt/" target="_blank" rel="noreferrer">VLK (National Health Insurance Fund)</a></li><li><a href="https://www.lithuania.travel/en/relocate" target="_blank" rel="noreferrer">Lithuania - Work &amp; Live</a></li><li><a href="https://www.lgl.lt/" target="_blank" rel="noreferrer">LGL (National LGBT Rights Organization)</a></li><li><a href="https://transautonomija.lt/" target="_blank" rel="noreferrer">Trans Autonomija</a></li><li><a href="https://www.aruodas.lt/" target="_blank" rel="noreferrer">Aruodas (housing)</a></li></ul>',27))])}const v=o(h,[["render",u]]);export{y as __pageData,v as default};
